def mergeTwoLists(list1, list2):
    def list_to_linked(arr):
        if not arr: return None
        head = ListNode(arr[0])
        curr = head
        for val in arr[1:]:
            curr.next = ListNode(val)
            curr = curr.next
        return head

    def linked_to_list(head):
        result = []
        while head:
            result.append(head.val)
            head = head.next
        return result

    l1 = list_to_linked(list1)
    l2 = list_to_linked(list2)

    dummy = ListNode(0)
    curr = dummy

    while l1 and l2:
        if l1.val <= l2.val:
            curr.next = l1
            l1 = l1.next
        else:
            curr.next = l2
            l2 = l2.next
        curr = curr.next

    curr.next = l1 or l2
    return linked_to_list(dummy.next)

