def getIntersectionNode(listA, listB, skipA=0, skipB=0):
    def create_lists(listA, listB, skipA, skipB):
        if not listA or not listB:
            return None, None

        nodesA = [ListNode(val) for val in listA]
        nodesB = [ListNode(val) for val in listB]

        for i in range(len(nodesA) - 1):
            nodesA[i].next = nodesA[i + 1]

        for i in range(len(nodesB) - 1):
            nodesB[i].next = nodesB[i + 1]

        # Create intersection
        if skipA < len(nodesA) and skipB < len(nodesB):
            nodesB[skipB - 1].next = nodesA[skipA]

        return nodesA[0], nodesB[0]

    if isinstance(listA, list):
        headA, headB = create_lists(listA, listB, skipA, skipB)
    else:
        headA, headB = listA, listB

    if not headA or not headB:
        return None

    pA, pB = headA, headB

    while pA != pB:
        pA = pA.next if pA else headB
        pB = pB.next if pB else headA

    return pA.val if pA else None

